Both_WIZ_and_Defender_CVE_is_not_exits.inputs:
@if(
  and(
    contains(
      body('Machine_Details_from_CVE_Details')?['CVE-details'],
      'CVE-ID does not exist in our environment'
    ),
    empty(
      body('Effected_Devices_details_of_CVE_from_WIZ')?['Device_Details']
    )
  ),
  true,
  false
)

CIV_exits_in_WIZ_but_not_in_Defender.inputs:
@if(
  and(
    contains(
      body('Machine_Details_from_CVE_Details')?['CVE-details'],
      'CVE-ID does not exist in our environment'
    ),
    not(
      empty(
        body('Effected_Devices_details_of_CVE_from_WIZ')?['Device_Details']
      )
    )
  ),
  true,
  false
)

