  "$schema": "https://adaptivecards.io/schemas/adaptive-card.json",
  "type": "AdaptiveCard",
  "version": "1.5",
  "body": [
 {
      "type": "FactSet",
      "facts": [
	        {
	           "title": "Title:",
	           "value": "@{triggerBody()?['title']}"
        	},
        {
          "title": "Feed Summary:",
          "value": "@{outputs('HTML_to_text')}"
        },
        {
