          "value": "[?? View CVE Feed](@{triggerBody()?['primaryLink']})"
        }
      ]
},
    {
      "type": "TextBlock",
      "text": "?? Critical Vulnerability Alert",
      "size": "Large",
      "weight": "Bolder",
      "color": "Attention",
      "wrap": true
    },
    {
      "type": "TextBlock",
      "text": "Automated CVE correlation from Microsoft Defender & WIZ",
      "isSubtle": true,
      "wrap": true
    },

    /* ================= DEFENDER SECTION ================= */

    {
      "type": "Container",
      "style": "attention",
      "spacing": "Medium",
      "items": [
        {
          "type": "TextBlock",
          "text": "??? CVE Details (Defender)",
          "weight": "Bolder"
        },
        {
          "type": "FactSet",
          "facts": @{outputs('Defender_CVE_Device_Affected_Details')}
       }
     ]
    },

    {
      "type": "Container",
      "style": "warning",
      "isVisible": @{outputs('Check_CVE_Device_exists')},
      "$when": "${defenderDevicesCount == 0}",
      "items": [
        {
          "type": "TextBlock",
          "text": "?? Device Impact (Defender)",
          "weight": "Bolder"
        },
        {
          "type": "TextBlock",
          "text": "?? No devices affected in Microsoft Defender",
          "color": "Warning"
        }
      ]
    },

    {
      "type": "Container",
      "style": "emphasis",
      "isVisible": @{if(
  equals(outputs('Check_CVE_Device_exists'), 'true'),
  'false',
  'true'
)},
      "$when": "${defenderDevicesCount > 0}",
      "items": [
        {
          "type": "TextBlock",
          "text": "?? Affected Devices (Defender)",
          "weight": "Bolder",
          "color": "Accent"
        },
        {
          "type": "ColumnSet",
          "columns": [
            {
              "type": "Column",
              "width": "auto",
              "items": [{ "type": "TextBlock", "text": "CVE ID", "weight": "Bolder" }]
            },
            {
              "type": "Column",
              "width": "stretch",
              "items": [{ "type": "TextBlock", "text": "Device Name", "weight": "Bolder" }]
            }
          ]
        },
        @{outputs('String_to_Json_of_Defender')}
      ]
    },

    /* ================= WIZ SECTION ================= */

    {
      "type": "Container",
      "style": "emphasis",
      "spacing": "Medium",
      "items": [
        {
          "type": "TextBlock",
          "text": "?? CVE Details (WIZ)",
          "weight": "Bolder",
          "color": "Accent"
        },
        {
          "type": "FactSet",
          "facts": @{outputs('WIZ_CVE_Device_Affected_Details')}
         }
       ]
    },

    /* ---- WIZ: NO DEVICE AFFECTED ---- */
    {
      "type": "Container",
      "style": "warning",
      "isVisible": @{outputs('Check_CVE_Device_exists_for_WIZ')},
      "$when": "${wizDevicesCount == 0}",
      "items": [
        {
          "type": "TextBlock",
          "text": "??? Device Impact (WIZ)",
          "weight": "Bolder"
        },
        {
          "type": "TextBlock",
          "text": "?? No affected workloads found in WIZ",
          "color": "Warning"
        }
      ]
    },

    /* ---- WIZ: AFFECTED DEVICES ---- */
    {
      "type": "Container",
      "style": "emphasis",
      "isVisible": @{if(
  equals(outputs('Check_CVE_Device_exists_for_WIZ'), 'true'),
  'false',
  'true'
)},
      "$when": "${wizDevicesCount > 0}",
      "items": [
        {
          "type": "TextBlock",
          "text": "??? Affected Devices (WIZ)",
          "weight": "Bolder",
          "color": "Accent"
        },
        {
          "type": "ColumnSet",
          "columns": [
            {
              "type": "Column",
              "width": "auto",
              "items": [{ "type": "TextBlock", "text": "CVE ID", "weight": "Bolder" }]
            },
            {
              "type": "Column",
              "width": "stretch",
              "items": [{ "type": "TextBlock", "text": "Asset Name", "weight": "Bolder" }]
            }
          ]
        },
       @{outputs('String_to_json_of_WIZ')}
      ]
    },

    {
      "type": "TextBlock",
      "text": "? Generated by SOAR Automation | Threat_intel_feed_hackersnews_logic_App",
      "isSubtle": true,
      "spacing": "Medium"
    }
  ]
}

